const biz = $input.first().json;
const now = new Date();
const fecha_publicacion = now.toISOString().slice(0,10);
const YYYYMM = fecha_publicacion.slice(0,7).replace('-','');
const utm_campaign = (biz.nombre_empresa || '').replace(/\s+/g,'') + '_' + YYYYMM;
const utm = JSON.stringify({ source: biz.plataforma_principal, medium: 'social', campaign: utm_campaign, content: 'pieza_unica' });

const system_prompt = `Eres el estratega de contenido de ${biz.nombre_empresa}, negocio de ${biz.nicho}.
Tono: ${biz.tono}. Publico: ${biz.publico_objetivo}. Productos: ${biz.productos_servicios}. Plataforma principal: ${biz.plataforma_principal}. Objetivo: ${biz.objetivo_principal}.

Genera UNA pieza de contenido para el ${fecha_publicacion} que conecte un dolor real de ese publico con uno de los productos, y cierre con una accion clara.
Estilo: humano y cercano, sin cliches de IA (nada de "revoluciona", "en la era digital"). Incluye una microprueba (dato o ejemplo).

Responde UNICAMENTE con JSON valido, sin texto extra, con estas llaves:
- "idea": concepto central en 1 frase.
- "caption": listo para publicar (gancho, dolor, beneficio+microprueba, CTA). Maximo 80 palabras.
- "hashtags": array de 4 a 6 strings.
- "image_prompt": escena fotografica realista (sujeto, entorno, luz), sin texto ni marcas de agua, aspect_ratio 4:5.`;

return [{ json: { ...biz, fecha_publicacion, YYYYMM, utm_campaign, system_prompt } }];

const resp = $input.first().json;
const textoBruto = resp.message.content;
const limpio = textoBruto.trim().replace(/^```json\s*/i, '').replace(/```\s*$/, '');
const contenido = JSON.parse(limpio);
return [{ json: contenido }];

